  6→import { createHash } from 'node:crypto'
  7→import { readFileSync, existsSync } from 'node:fs'
  8→
  9→import type { TranscriptMessage, TranscriptToolEvent } from '../types/transcript.js'
 10→
 11→// ---------------------------------------------------------------------------
 12→// Constants
 13→// ---------------------------------------------------------------------------
 14→
 15→export const CLIENTS: ReadonlySet<string> = new Set(['codex', 'claude', 'gemini'])
 16→export const TEXT_BLOCK_TYPES: ReadonlySet<string> = new Set(['input_text', 'output_text', 'text'])
 17→export const SKIP_BLOCK_TYPES: ReadonlySet<string> = new Set(['thinking', 'reasoning'])
 18→export const TOOL_USE_TYPES: ReadonlySet<string> = new Set(['tool_use'])
 19→export const TOOL_RESULT_TYPES: ReadonlySet<string> = new Set(['tool_result'])
 20→
 21→// ---------------------------------------------------------------------------
 22→// Generic utilities
 23→// ---------------------------------------------------------------------------
 24→
 25→export function slugify(value: string, fallback = 'session'): string {
 26→  const asciiValue = value.replace(/[^\x00-\x7F]/g, '').toLowerCase()
 27→  const slug = asciiValue.replace(/[^a-z0-9._-]+/g, '-').replace(/^[-._]+|[-._]+$/g, '')
 28→  return slug || fallback
 29→}
 30→
 31→export function sha256File(filePath: string): string {
 32→  const data = readFileSync(filePath)
 33→  return createHash('sha256').update(data).digest('hex')
 34→}
 35→
 36→export function contentHash(text: string): string {
 37→  return createHash('sha256').update(text, 'utf8').digest('hex').slice(0, 16)
 38→}
 39→
 40→export function normalizeTimestamp(value: unknown, fallback?: string | null): string {
 41→  if (typeof value === 'number') {
 42→    const ms = value < 1e12 ? value * 1000 : value
 43→    const d = new Date(ms)
 44→    return formatUtcIso(d)
 45→  }
 46→
 47→  if (value instanceof Date) {
 48→    return formatUtcIso(value)
 49→  }
 50→
 51→  if (typeof value === 'string') {
 52→    const text = value.trim()
 53→    if (!text) {
 54→      return fallback ?? normalizeTimestamp(new Date())
 55→    }
 56→    const parsed = parseIsoTimestamp(text)
 57→    if (parsed !== null) {
 58→      return formatUtcIso(parsed)
 59→    }
 60→    return text
 61→  }
 62→
 63→  return fallback ?? normalizeTimestamp(new Date())
 64→}
 65→
 66→export function earliestTimestamp(current: string, candidate: unknown): string {
 67→  const normalized = normalizeTimestamp(candidate, current)
 68→  const currentDt = parseIsoTimestamp(current)
 69→  const normalizedDt = parseIsoTimestamp(normalized)
 70→  if (currentDt !== null && normalizedDt !== null) {
 71→    return normalizedDt < currentDt ? normalized : current
 72→  }
 73→  if (normalizedDt !== null) {
 74→    return normalized
 75→  }
 76→  return current || normalized
 77→}
 78→
 79→export function parseIsoTimestamp(value: string): Date | null {
 80→  if (!value) return null
 81→  const candidate = value.endsWith('Z') ? value.slice(0, -1) + '+00:00' : value
 82→  const d = new Date(candidate)
 83→  if (isNaN(d.getTime())) return null
 84→  return d
 85→}
 86→
 87→export function timestampPartition(timestamp: string): [string, string] {
 88→  const d = parseIsoTimestamp(timestamp)
 89→  if (d === null) return ['unknown', 'unknown']
 90→  const year = d.getUTCFullYear().toString()
 91→  const month = (d.getUTCMonth() + 1).toString().padStart(2, '0')
 92→  return [year, month]
 93→}
 94→
 95→export function joinParagraphs(parts: Iterable<string>): string {
 96→  const cleaned: string[] = []
 97→  for (const part of parts) {
 98→    const trimmed = String(part).trim()
 99→    if (trimmed) cleaned.push(trimmed)
100→  }
101→  return cleaned.join('\n\n')
102→}
103→
104→export function summarizeValue(value: unknown, limit = 180): string {
105→  if (value === null || value === undefined) return 'none'
106→  if (typeof value === 'string') {
107→    const text = value.replace(/\s+/g, ' ').trim()
108→    return truncate(text, limit)
109→  }
110→  let text: string
111→  try {
112→    text = JSON.stringify(value, Object.keys(value as Record<string, unknown>).sort())
113→  } catch {
114→    text = String(value)
115→  }
116→  text = text.replace(/\s+/g, ' ').trim()
117→  return truncate(text, limit)
118→}
119→
120→export function truncate(text: string, limit: number): string {
121→  return text.length <= limit ? text : text.slice(0, limit - 3) + '...'
122→}
123→
124→export function yamlEscape(value: string): string {
125→  const escaped = value.replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, '\\n')
126→  return `"${escaped}"`
127→}
128→
129→// ---------------------------------------------------------------------------
130→// Data access helpers
131→// ---------------------------------------------------------------------------
132→
133→export function ensureDict(value: unknown): Record<string, unknown> {
134→  if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
135→    return value as Record<string, unknown>
136→  }
137→  return {}
138→}
139→
140→export function ensureList(value: unknown): unknown[] {
141→  return Array.isArray(value) ? value : []
142→}
143→
144→export function getNested(payload: Record<string, unknown>, ...keys: string[]): unknown {
145→  let current: unknown = payload
146→  for (const key of keys) {
147→    if (current === null || typeof current !== 'object' || Array.isArray(current)) {
148→      return null
149→    }
150→    current = (current as Record<string, unknown>)[key]
151→  }
152→  return current ?? null
153→}
154→
155→export function loadJsonl(filePath: string): Record<string, unknown>[] {
156→  let content: string
157→  try {
158→    content = readFileSync(filePath, 'utf-8')
159→  } catch {
160→    return []
161→  }
162→  const records: Record<string, unknown>[] = []
163→  for (const line of content.split('\n')) {
164→    const trimmed = line.trim()
165→    if (!trimmed) continue
166→    try {
167→      records.push(JSON.parse(trimmed) as Record<string, unknown>)
168→    } catch {
169→      continue
170→    }
171→  }
172→  return records
173→}
174→
175→export function loadJson(filePath: string): Record<string, unknown> | null {
176→  if (!existsSync(filePath)) return null
177→  try {
178→    const text = readFileSync(filePath, 'utf-8')
179→    return JSON.parse(text) as Record<string, unknown>
180→  } catch {
181→    return null
182→  }
183→}
184→
185→// ---------------------------------------------------------------------------
186→// Text extraction helpers
187→// ---------------------------------------------------------------------------
188→
189→export function extractTextBlocks(blocks: unknown): string {
190→  const parts: string[] = []
191→  const skipTypes = new Set([...SKIP_BLOCK_TYPES, ...TOOL_USE_TYPES, ...TOOL_RESULT_TYPES])
192→
193→  for (const block of ensureList(blocks)) {
194→    if (typeof block === 'string') {
195→      const text = block.trim()
196→      if (text) parts.push(text)
197→      continue
198→    }
199→    if (block === null || typeof block !== 'object' || Array.isArray(block)) continue
200→
201→    const rec = block as Record<string, unknown>
202→    const blockType = String(rec['type'] ?? '').toLowerCase()
203→    if (skipTypes.has(blockType)) continue
204→    if (TEXT_BLOCK_TYPES.has(blockType)) {
205→      const text = String(rec['text'] ?? '').trim()
206→      if (text) parts.push(text)
207→      continue
208→    }
209→    const fallbackText = extractSimpleText(block)
210→    if (fallbackText) parts.push(fallbackText)
211→  }
212→  return joinParagraphs(parts)
213→}
214→
215→export function extractSimpleText(value: unknown): string {
216→  if (typeof value === 'string') return value.trim()
217→  if (Array.isArray(value)) {
218→    return joinParagraphs(value.map(item => extractSimpleText(item)))
219→  }
220→  if (value !== null && typeof value === 'object') {
221→    const rec = value as Record<string, unknown>
222→    for (const key of ['text', 'content', 'value']) {
223→      if (key in rec && typeof rec[key] === 'string') {
224→        return (rec[key] as string).trim()
225→      }
226→    }
227→    return ''
228→  }
229→  return ''
230→}
231→
232→export function extractGeminiText(node: Record<string, unknown>): string {
233→  const parts: string[] = []
234→  for (const key of ['parts', 'content', 'text', 'message']) {
235→    parts.push(...extractGeminiParts(node[key]))
236→  }
237→  return joinParagraphs(parts)
238→}
239→
240→export function extractGeminiParts(value: unknown): string[] {
241→  if (typeof value === 'string') {
242→    const text = value.trim()
243→    return text ? [text] : []
244→  }
245→  if (Array.isArray(value)) {
246→    const parts: string[] = []
247→    for (const item of value) {
248→      parts.push(...extractGeminiParts(item))
249→    }
250→    return parts
251→  }
252→  if (value !== null && typeof value === 'object') {
253→    const rec = value as Record<string, unknown>
254→    const blockType = String(rec['type'] ?? '').toLowerCase()
255→    const skipTypes = new Set([...SKIP_BLOCK_TYPES, ...TOOL_USE_TYPES, ...TOOL_RESULT_TYPES])
256→    if (skipTypes.has(blockType)) return []
257→    if ('text' in rec && typeof rec['text'] === 'string') {
258→      const text = (rec['text'] as string).trim()
259→      return text ? [text] : []
260→    }
261→    const parts: string[] = []
262→    for (const key of ['parts', 'content']) {
263→      if (key in rec) {
264→        parts.push(...extractGeminiParts(rec[key]))
265→      }
266→    }
267→    return parts
268→  }
269→  return []
270→}
271→
272→export function findFirstMappingWithKeys(value: unknown, keys: ReadonlySet<string>): Record<string, unknown> | null {
273→  if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
274→    const rec = value as Record<string, unknown>
275→    const recKeys = Object.keys(rec)
276→    if (recKeys.some(k => keys.has(k))) return rec
277→    for (const v of Object.values(rec)) {
278→      const result = findFirstMappingWithKeys(v, keys)
279→      if (result !== null) return result
280→    }
281→    return null
282→  }
283→  if (Array.isArray(value)) {
284→    for (const item of value) {
285→      const result = findFirstMappingWithKeys(item, keys)
286→      if (result !== null) return result
287→    }
288→  }
289→  return null
290→}
291→
292→// ---------------------------------------------------------------------------
293→// Deduplication helpers
294→// ---------------------------------------------------------------------------
295→
296→export function deduplicateMessages(messages: readonly TranscriptMessage[]): TranscriptMessage[] {
297→  const seen = new Set<string>()
298→  const result: TranscriptMessage[] = []
299→  for (const msg of messages) {
300→    const sig = `${msg.timestamp ?? ''}\0${msg.role}\0${contentHash(msg.text)}`
301→    if (!seen.has(sig)) {
302→      seen.add(sig)
303→      result.push(msg)
304→    }
305→  }
306→  return result
307→}
308→
309→export function deduplicateToolEvents(events: readonly TranscriptToolEvent[]): TranscriptToolEvent[] {
310→  const seen = new Set<string>()
311→  const result: TranscriptToolEvent[] = []
312→  for (const evt of events) {
313→    const sig = `${evt.timestamp ?? ''}\0${contentHash(evt.summary)}`
314→    if (!seen.has(sig)) {
315→      seen.add(sig)
316→      result.push(evt)
317→    }
318→  }
319→  return result
320→}
321→
322→// ---------------------------------------------------------------------------
323→// Internal helpers
324→// ---------------------------------------------------------------------------
325→
326→function formatUtcIso(d: Date): string {
327→  const year = d.getUTCFullYear()
328→  const month = String(d.getUTCMonth() + 1).padStart(2, '0')
329→  const day = String(d.getUTCDate()).padStart(2, '0')
330→  const hours = String(d.getUTCHours()).padStart(2, '0')
331→  const minutes = String(d.getUTCMinutes()).padStart(2, '0')
332→  const seconds = String(d.getUTCSeconds()).padStart(2, '0')
333→  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}Z`
334→}
